+        let mut b = vec![4.0, 5.0, 6.0];
+
+        l2_normalize(&mut a);
+        l2_normalize(&mut b);
+
+        let cosine = dot_product(&a, &b);
+        // Cosine similarity of [1,2,3] and [4,5,6] = 32 / (√14 * √77) ≈ 0.9746
